#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Execute a SQL query on a warehouse
 *
 * This example demonstrates:
 * - Executing a SQL statement on a warehouse
 * - Waiting for query completion
 * - Fetching query results
 * - Handling result sets
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - An existing SQL warehouse ID (set TEST_WAREHOUSE_ID environment variable)
 *
 * Usage:
 *   export TEST_WAREHOUSE_ID="your-warehouse-id"
 *   npx ts-node examples/workspace/sql/execute-query.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const warehouseId = process.env.TEST_WAREHOUSE_ID;

    if (!warehouseId) {
        console.error(
            "✗ Error: TEST_WAREHOUSE_ID environment variable not set"
        );
        console.error("  Please set it to an existing SQL warehouse ID.");
        process.exit(1);
    }

    console.log(`Executing query on warehouse: ${warehouseId}\n`);

    try {
        // Simple SELECT query
        const query =
            "SELECT 'Hello from Databricks SDK!' as greeting, current_timestamp() as timestamp";

        console.log(`Query: ${query}`);
        console.log(`\nExecuting...`);

        // Execute the query
        const statement = await client.statementExecution.executeStatement({
            warehouse_id: warehouseId,
            statement: query,
            wait_timeout: "30s",
        });

        console.log(`✓ Query executed`);
        console.log(`  Statement ID: ${statement.statement_id}`);
        console.log(`  Status: ${statement.status?.state}`);

        // Display results
        if (statement.result?.data_array) {
            console.log(`\nResults:`);

            // Get column names from schema
            const columns =
                statement.manifest?.schema?.columns?.map((col) => col.name) ||
                [];

            // Convert rows to objects for console.table
            const rows = statement.result.data_array.map((row) => {
                const rowObj: Record<string, any> = {};
                columns.forEach((col, idx) => {
                    rowObj[col || `col${idx}`] = row[idx];
                });
                return rowObj;
            });

            console.table(rows);
            console.log(`Total rows: ${statement.result.row_count || 0}`);
        }

        // Example: Query with multiple rows
        console.log(`\n--- Example: Query with multiple rows ---\n`);

        const multiRowQuery =
            "SELECT explode(sequence(1, 5)) as number, current_date() as date";

        console.log(`Query: ${multiRowQuery}`);
        console.log(`\nExecuting...`);

        const multiRowStatement =
            await client.statementExecution.executeStatement({
                warehouse_id: warehouseId,
                statement: multiRowQuery,
                wait_timeout: "30s",
            });

        console.log(`✓ Query executed`);

        if (multiRowStatement.result?.data_array) {
            console.log(`\nResults:`);

            const columns =
                multiRowStatement.manifest?.schema?.columns?.map(
                    (col) => col.name
                ) || [];

            // Convert rows to objects for console.table
            const rows = multiRowStatement.result.data_array.map((row) => {
                const rowObj: Record<string, any> = {};
                columns.forEach((col, idx) => {
                    rowObj[col || `col${idx}`] = row[idx];
                });
                return rowObj;
            });

            console.table(rows);
            console.log(
                `Total rows: ${multiRowStatement.result.row_count || 0}`
            );
        }

        console.log(`\n✓ Query execution examples complete`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
